import{_ as n,o as a,c as e,ag as p}from"./chunks/framework.BZohXCq9.js";const d=JSON.parse('{"title":"第八章：自适应检索与噪声过滤","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/08-adaptive-noise.md","filePath":"chapters/08-adaptive-noise.md"}'),l={name:"chapters/08-adaptive-noise.md"};function i(t,s,r,o,c,u){return a(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="第八章-自适应检索与噪声过滤" tabindex="-1">第八章：自适应检索与噪声过滤 <a class="header-anchor" href="#第八章-自适应检索与噪声过滤" aria-label="Permalink to &quot;第八章：自适应检索与噪声过滤&quot;">​</a></h1><blockquote><p>不是所有对话都值得检索记忆。当用户说&quot;你好&quot;、输入一个 emoji、或者敲下 <code>/clear</code> 命令时，触发一次完整的混合检索管线是纯粹的资源浪费。更糟糕的是，这些无意义的查询可能召回不相关的记忆，干扰 LLM 的上下文。memory-lancedb-pro 用三道防线解决这个问题：自适应检索在入口处拦截无效查询，噪声过滤在出口处清除低质量结果，噪声原型库则用 embedding 的方式实现语言无关的噪声识别与自学习。</p></blockquote><h2 id="_8-1-自适应检索-入口处的守门员" tabindex="-1">8.1 自适应检索：入口处的守门员 <a class="header-anchor" href="#_8-1-自适应检索-入口处的守门员" aria-label="Permalink to &quot;8.1 自适应检索：入口处的守门员&quot;">​</a></h2><p><code>adaptive-retrieval.ts</code> 是一个精巧的 100 行模块，它在检索管线的最前端做出三种判断：跳过（skip）、强制触发（force）、或正常通过（normal）。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/adaptive-retrieval.ts L10-30</span></span>
<span class="line"><span>// 查询分类逻辑：</span></span>
<span class="line"><span>// 1. 先检查是否应该跳过（skip）</span></span>
<span class="line"><span>// 2. 再检查是否应该强制检索（force）</span></span>
<span class="line"><span>// 3. 最后检查最小长度要求</span></span>
<span class="line"><span>// 4. 通过所有检查 → normal（正常进入管线）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>为什么跳过检查在强制检查之前？</strong> 这个优先级设计是经过深思熟虑的。考虑一个边界情况：用户输入 &quot;/remember&quot;——它同时匹配命令模式（以 / 开头）和强制触发关键词（&quot;remember&quot;）。如果先检查强制触发，这个明显的命令输入就会触发一次检索。通过将跳过检查放在首位，我们确保了明确的无效输入不会被后续规则&quot;误救&quot;。</p><h3 id="skip-规则" tabindex="-1">Skip 规则 <a class="header-anchor" href="#skip-规则" aria-label="Permalink to &quot;Skip 规则&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/adaptive-retrieval.ts L35-55</span></span>
<span class="line"><span>// 跳过条件（任一满足即跳过）：</span></span>
<span class="line"><span>// 1. 问候语: hi, hello, hey, 你好, こんにちは 等</span></span>
<span class="line"><span>// 2. 命令: 以 / 开头的文本（如 /new, /clear, /help）</span></span>
<span class="line"><span>// 3. 肯定回应: ok, yes, sure, 好的, 没问题 等</span></span>
<span class="line"><span>// 4. 纯 emoji: 全部由 emoji 字符组成的消息</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这四类 skip 规则覆盖了对话中最常见的&quot;非信息性&quot;输入。它们的共同特征是：不包含任何可供检索的语义内容。对这类输入执行检索，最好的情况是浪费计算资源返回空结果，最坏的情况是召回不相关的记忆干扰后续对话。</p><p><strong>问候语识别为什么需要多语言支持？</strong> memory-lancedb-pro 定位为全球可用的记忆插件。一个只能识别英文 &quot;hello&quot; 但无法识别中文&quot;你好&quot;或日文&quot;こんにちは&quot;的跳过规则，在非英语环境中形同虚设。多语言问候语列表虽然增加了维护成本，但对系统的实际可用性至关重要。</p><h3 id="force-规则" tabindex="-1">Force 规则 <a class="header-anchor" href="#force-规则" aria-label="Permalink to &quot;Force 规则&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/adaptive-retrieval.ts L60-80</span></span>
<span class="line"><span>// 强制检索条件（任一满足即强制触发）：</span></span>
<span class="line"><span>// 1. 英文记忆关键词: &quot;remember&quot;, &quot;recall&quot;, &quot;last time&quot;,</span></span>
<span class="line"><span>//    &quot;previously&quot;, &quot;we discussed&quot; 等</span></span>
<span class="line"><span>// 2. CJK 记忆关键词: &quot;记得&quot;, &quot;上次&quot;, &quot;之前&quot;, &quot;提到过&quot; 等</span></span>
<span class="line"><span>// 3. 这些关键词明确表达了用户对历史记忆的检索意图</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Force 规则的存在解决了一个重要问题：某些查询可能因为太短而被最小长度规则过滤掉，但它们包含明确的检索意图。例如，用户说&quot;上次呢？&quot;——只有 4 个中文字符，低于很多长度阈值，但&quot;上次&quot;这个词明确表达了回忆历史信息的意图。Force 规则确保了这类查询不会被误过滤。</p><h3 id="最小长度要求" tabindex="-1">最小长度要求 <a class="header-anchor" href="#最小长度要求" aria-label="Permalink to &quot;最小长度要求&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/adaptive-retrieval.ts L85-100</span></span>
<span class="line"><span>// 最小长度阈值：</span></span>
<span class="line"><span>// 英文: 15 个字符</span></span>
<span class="line"><span>// CJK: 6 个字符</span></span>
<span class="line"><span>//</span></span>
<span class="line"><span>// 为什么 CJK 阈值更低？</span></span>
<span class="line"><span>// 因为 CJK 文字的信息密度远高于拉丁字母</span></span>
<span class="line"><span>// &quot;数据库部署方案&quot; = 6 个字符，但信息量等同于</span></span>
<span class="line"><span>// &quot;database deployment plan&quot; = 24 个字符</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这个看似简单的长度检查背后是对语言特性的理解。中文一个字就是一个语素，而英文一个单词通常需要 4-7 个字符。如果对 CJK 文本使用与英文相同的字符数阈值，大量有效的中文查询都会被错误地跳过。6 个中文字符大约是 2-3 个词，足以表达一个有意义的检索意图。</p><p><strong>如何判断文本是 CJK 还是英文？</strong> 代码通过检测文本中 CJK Unicode 范围（U+4E00 - U+9FFF 等）字符的比例来判断。当 CJK 字符占比超过一定阈值时，使用 CJK 的最小长度规则。</p><h2 id="_8-2-噪声过滤-出口处的质检员" tabindex="-1">8.2 噪声过滤：出口处的质检员 <a class="header-anchor" href="#_8-2-噪声过滤-出口处的质检员" aria-label="Permalink to &quot;8.2 噪声过滤：出口处的质检员&quot;">​</a></h2><p>如果说自适应检索是在入口处拦截无效查询，<code>noise-filter.ts</code> 则是在出口处清除低质量结果。即使查询通过了自适应检索的检查，检索管线返回的候选中仍然可能包含噪声记忆——那些不应该被呈现给 LLM 的内容。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/noise-filter.ts L10-25</span></span>
<span class="line"><span>// 噪声过滤器的定位：</span></span>
<span class="line"><span>// 检索管线的最后几步之一（在 hardMinScore 之后）</span></span>
<span class="line"><span>// 通过正则表达式模式匹配识别噪声内容</span></span>
<span class="line"><span>// 匹配到噪声模式的记忆条目会被从结果中移除</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="agent-拒绝模式" tabindex="-1">Agent 拒绝模式 <a class="header-anchor" href="#agent-拒绝模式" aria-label="Permalink to &quot;Agent 拒绝模式&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/noise-filter.ts L30-55</span></span>
<span class="line"><span>// 15 种 agent 拒绝模式，例如：</span></span>
<span class="line"><span>// - &quot;I cannot help with that&quot;</span></span>
<span class="line"><span>// - &quot;I&#39;m not able to&quot;</span></span>
<span class="line"><span>// - &quot;As an AI language model&quot;</span></span>
<span class="line"><span>// - &quot;I don&#39;t have access to&quot;</span></span>
<span class="line"><span>// - &quot;我无法帮助你&quot;</span></span>
<span class="line"><span>// - &quot;作为一个 AI&quot;</span></span>
<span class="line"><span>// ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>为什么要过滤 agent 拒绝内容？</strong> 这些内容是 LLM 自身产生的拒绝回复，不包含任何用户信息。如果它们被存储为&quot;记忆&quot;（可能因为记忆提取逻辑的误判），然后在后续对话中被召回，会导致 LLM 误认为自己之前拒绝过类似请求，从而影响当前回复的质量。过滤掉这些内容是对记忆质量的一种保护。</p><h3 id="元问题模式" tabindex="-1">元问题模式 <a class="header-anchor" href="#元问题模式" aria-label="Permalink to &quot;元问题模式&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/noise-filter.ts L60-90</span></span>
<span class="line"><span>// 20+ 种元问题模式（含 CJK 变体），例如：</span></span>
<span class="line"><span>// - &quot;What can you help me with?&quot;</span></span>
<span class="line"><span>// - &quot;What are your capabilities?&quot;</span></span>
<span class="line"><span>// - &quot;你能做什么？&quot;</span></span>
<span class="line"><span>// - &quot;你有什么功能？&quot;</span></span>
<span class="line"><span>// - &quot;どのようなことができますか？&quot;</span></span>
<span class="line"><span>// ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>元问题是用户询问 AI 能力边界的问题——&quot;你能做什么？&quot;、&quot;你有什么功能？&quot;。这类问题的回答没有长期记忆价值（AI 的能力边界应该由系统提示而非记忆决定），但它们在向量空间中可能与各种话题相关（因为它们本质上是在问&quot;所有话题&quot;），导致被频繁召回。过滤它们可以显著减少噪声干扰。</p><h3 id="样板文本" tabindex="-1">样板文本 <a class="header-anchor" href="#样板文本" aria-label="Permalink to &quot;样板文本&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/noise-filter.ts L95-110</span></span>
<span class="line"><span>// 样板文本模式：</span></span>
<span class="line"><span>// - &quot;hi&quot;, &quot;hello&quot;（单独出现的问候）</span></span>
<span class="line"><span>// - &quot;/new&quot;, &quot;/clear&quot; 等命令</span></span>
<span class="line"><span>// - &quot;HEARTBEAT&quot;（某些系统的心跳消息）</span></span>
<span class="line"><span>// 这些内容如果被误存为记忆，需要在出口处兜底过滤</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>为什么自适应检索已经跳过了问候语，这里还要再过滤？</strong> 因为自适应检索过滤的是查询端，而噪声过滤过滤的是结果端。一条包含&quot;hello&quot;的记忆可能在自适应检索引入之前就已经被存储了，或者是从对话中提取记忆时的误提取。噪声过滤是最后一道防线，确保无论记忆是何时、如何进入系统的，噪声内容都不会出现在最终结果中。</p><h2 id="_8-3-噪声原型库-基于-embedding-的自学习噪声识别" tabindex="-1">8.3 噪声原型库：基于 Embedding 的自学习噪声识别 <a class="header-anchor" href="#_8-3-噪声原型库-基于-embedding-的自学习噪声识别" aria-label="Permalink to &quot;8.3 噪声原型库：基于 Embedding 的自学习噪声识别&quot;">​</a></h2><p><code>noise-prototypes.ts</code> 是三层噪声防护中最精巧的一层。与正则表达式的&quot;硬编码&quot;模式不同，它使用 embedding 向量来识别噪声，实现了语言无关的噪声检测，并且能够从运行时数据中自动学习新的噪声模式。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/noise-prototypes.ts L10-40</span></span>
<span class="line"><span>// 噪声原型库的核心思想：</span></span>
<span class="line"><span>// 1. 预定义一组&quot;种子&quot;噪声原型（15 个）</span></span>
<span class="line"><span>// 2. 将每个原型编码为 embedding 向量</span></span>
<span class="line"><span>// 3. 新输入与所有原型计算余弦相似度</span></span>
<span class="line"><span>// 4. 如果最高相似度超过阈值 → 判定为噪声</span></span>
<span class="line"><span>// 5. 运行时发现的新噪声 → 加入原型库（自学习）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="_15-个种子原型" tabindex="-1">15 个种子原型 <a class="header-anchor" href="#_15-个种子原型" aria-label="Permalink to &quot;15 个种子原型&quot;">​</a></h3><p>种子原型覆盖了最常见的噪声类别。它们不是简单的关键词，而是完整的短文本，经过 embedding 编码后在向量空间中&quot;占据&quot;噪声区域。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/noise-prototypes.ts L50-100</span></span>
<span class="line"><span>// 种子原型示例：</span></span>
<span class="line"><span>// - &quot;Hello, how can I help you today?&quot;（问候）</span></span>
<span class="line"><span>// - &quot;I&#39;m an AI assistant created by...&quot;（自我介绍）</span></span>
<span class="line"><span>// - &quot;Sure, I&#39;d be happy to help!&quot;（空洞确认）</span></span>
<span class="line"><span>// - &quot;Is there anything else you need?&quot;（会话结束语）</span></span>
<span class="line"><span>// - &quot;Let me think about that...&quot;（填充语）</span></span>
<span class="line"><span>// ...</span></span>
<span class="line"><span>// 这些原型的选择标准：</span></span>
<span class="line"><span>// 高频出现、零信息量、跨语言普遍存在</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>为什么用 embedding 而不是更多的正则表达式？</strong> 正则表达式是精确匹配工具，它只能匹配预定义的文本模式。但噪声的表达方式是无限多样的——&quot;I&#39;m happy to help&quot; 和 &quot;I&#39;d be glad to assist&quot; 和 &quot;乐意为您效劳&quot; 表达的是同一种噪声语义，但没有任何正则表达式能同时匹配这三种表述。Embedding 方法通过语义空间的距离计算，可以将这些表面不同但语义相近的噪声统一识别。</p><p>更重要的是，embedding 方法天然支持多语言。一个英文噪声原型&quot;Hello, how can I help you?&quot;的 embedding 向量，与其中文对应&quot;你好，有什么可以帮你的？&quot;的向量在空间中是接近的（假设使用多语言 embedding 模型）。这意味着我们不需要为每种语言单独维护噪声列表。</p><h3 id="自学习机制" tabindex="-1">自学习机制 <a class="header-anchor" href="#自学习机制" aria-label="Permalink to &quot;自学习机制&quot;">​</a></h3><p>噪声原型库最令人印象深刻的特性是它的自学习能力：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/noise-prototypes.ts L200-250</span></span>
<span class="line"><span>// 自学习流程：</span></span>
<span class="line"><span>// 1. 记忆提取模块处理一段对话后得到零条有效记忆</span></span>
<span class="line"><span>//    （zero-extraction：没有提取出任何值得存储的信息）</span></span>
<span class="line"><span>// 2. 这段对话文本被视为&quot;疑似噪声&quot;</span></span>
<span class="line"><span>// 3. 计算其 embedding，与现有原型库去重（阈值 0.95）</span></span>
<span class="line"><span>// 4. 如果与所有现有原型的最大相似度 &lt; 0.95 → 新噪声模式</span></span>
<span class="line"><span>// 5. 将其加入原型库</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>为什么用&quot;零提取&quot;作为学习信号？</strong> 这是一个巧妙的启发式。如果记忆提取模块（通常由 LLM 驱动）分析了一段对话后认为没有任何信息值得存储，那么这段对话很可能确实是噪声。这不是一个完美的信号——有时候 LLM 可能遗漏了有价值的信息——但作为统计意义上的弱信号，它的准确率足够高。</p><h3 id="容量管理与去重" tabindex="-1">容量管理与去重 <a class="header-anchor" href="#容量管理与去重" aria-label="Permalink to &quot;容量管理与去重&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/noise-prototypes.ts L300-340</span></span>
<span class="line"><span>// 容量控制：</span></span>
<span class="line"><span>// maxPrototypes: 200</span></span>
<span class="line"><span>// 当原型数量达到上限时，移除最早加入的原型（FIFO）</span></span>
<span class="line"><span>//</span></span>
<span class="line"><span>// 去重阈值：</span></span>
<span class="line"><span>// dedupThreshold: 0.95</span></span>
<span class="line"><span>// 新原型与现有原型的余弦相似度 &gt; 0.95 → 视为重复，不加入</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>200 个原型的容量上限是一个平衡点。每次噪声检测需要计算输入与所有原型的余弦相似度，这是 O(n) 的操作。如果原型库无限增长，检测延迟会线性增加。200 个原型在保证覆盖率的同时将检测延迟控制在可接受范围内。</p><p>0.95 的去重阈值非常高，这意味着只有几乎完全相同的文本才会被视为重复。这个保守的阈值确保了原型库的多样性——&quot;I&#39;m happy to help you&quot;（相似度可能 0.92）和 &quot;I&#39;m glad to assist&quot;（相似度可能 0.88）会被视为两个不同的原型，分别覆盖向量空间中的不同区域。</p><h2 id="_8-4-三层防护的协同工作" tabindex="-1">8.4 三层防护的协同工作 <a class="header-anchor" href="#_8-4-三层防护的协同工作" aria-label="Permalink to &quot;8.4 三层防护的协同工作&quot;">​</a></h2><p>三个模块各司其职，但它们的协同效果远大于各自独立的贡献。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 文件: src/retriever.ts L800-850</span></span>
<span class="line"><span>// 三层噪声防护在检索管线中的位置：</span></span>
<span class="line"><span>// [输入] → adaptive-retrieval（入口守门）</span></span>
<span class="line"><span>//        ↓ 通过</span></span>
<span class="line"><span>// [检索管线 Step 1-7]</span></span>
<span class="line"><span>//        ↓</span></span>
<span class="line"><span>// noise-filter（出口质检，正则匹配）</span></span>
<span class="line"><span>//        ↓</span></span>
<span class="line"><span>// noise-prototypes（embedding 语义检测）</span></span>
<span class="line"><span>//        ↓</span></span>
<span class="line"><span>// [输出] 干净的检索结果</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p><strong>第一层（自适应检索）</strong> 在入口处拦截了大约 30-40% 的无效查询，节省了完整检索管线的计算成本。它的特点是快速——只需要几次字符串匹配和长度检查。</p><p><strong>第二层（噪声过滤器）</strong> 在出口处清除匹配已知噪声模式的结果。正则表达式的匹配速度极快（微秒级），即使结果集中有数十条候选也不会引入可感知的延迟。它的覆盖范围有限（只能匹配预定义的模式），但对已知噪声的清除是确定性的。</p><p><strong>第三层（噪声原型库）</strong> 补全了前两层的盲区。自适应检索只过滤查询端，不过滤结果端。正则过滤只匹配已知模式，无法应对新出现的噪声变体。噪声原型库通过 embedding 语义匹配覆盖了无限多的噪声表述形式，并且通过自学习机制不断扩展覆盖范围。</p><p>三层防护的叠加确保了 memory-lancedb-pro 的检索结果具有高信噪比。在生产环境中，这直接影响了 LLM 利用记忆的效果——干净的记忆让 LLM 能够准确回忆历史信息，而噪声记忆则会导致混乱、重复和幻觉。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>自适应检索、噪声过滤和噪声原型库构成了 memory-lancedb-pro 的三层噪声防护体系。自适应检索（<code>adaptive-retrieval.ts</code>）在入口处通过 skip/force/normal 三路分类拦截无效查询，其多语言关键词和差异化长度阈值（英文 15 字符、CJK 6 字符）体现了对语言特性的深入理解。噪声过滤器（<code>noise-filter.ts</code>）在出口处用正则表达式清除 agent 拒绝、元问题和样板文本三类已知噪声。噪声原型库（<code>noise-prototypes.ts</code>）是最精巧的一层：15 个种子原型通过 embedding 实现语言无关的噪声检测，零提取信号驱动的自学习机制使其覆盖范围随运行时间自动扩展，200 上限和 0.95 去重阈值平衡了覆盖率和性能。三层防护从快到精、从入口到出口、从硬编码到自学习，层层递进，共同保障了检索结果的信噪比。</p>`,54)])])}const m=n(l,[["render",i]]);export{d as __pageData,m as default};
